const events = []

function record(value) {
    events.push(value)
    log(events.join(' -> '))
}

async function main() {
    record('start')
    vmSleep(2).then(() => {
        record('later timer')
    })
    await vmSleep(1)
    debugger
    record('first after restore')
}

main()

